onClick:
{{
InsertActionPM.run({
  po: appsmith.store.selectedPMActionRow_PM?.MicrossSalesOrderReference,
  questionId: appsmith.store.selectedPMActionRow_PM?.QuestionId,
  responsible: Select_PMResponsiblePerson.selectedOptionValue,
  action: Input_PMAction.text,
  dueDate: Date_PMDue.selectedDate,

  // 🔥 FIXED
  actionId: appsmith.store.selectedPMActionRow_PM?.ActionId
})
.then(() => {
  showAlert("Sub Action created", "success");
  closeModal(Modal_PMAddAction.name);

  return Promise.all([
    GetPMQuestion.run()
  ]);
})
.catch((err) => {
  showAlert("Error creating action: " + err.message, "error");
});
}}
